#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    // 5 photographs, each with N IDs
    vector<vector<int>> photos(5, vector<int>(N));
    for (int p = 0; p < 5; ++p) {
        for (int i = 0; i < N; ++i) {
            cin >> photos[p][i];
        }
    }

    // For each cow, record in which positions (indices) it appears across photos
    // Since IDs are unique, we can map ID -> vector of 5 positions
    unordered_map<int, vector<int>> pos;
    for (int p = 0; p < 5; ++p) {
        for (int i = 0; i < N; ++i) {
            int id = photos[p][i];
            if (pos.find(id) == pos.end()) {
                pos[id] = vector<int>(5, -1); // -1 = not present? Actually all 5 photos have all N cows
            }
            pos[id][p] = i;
        }
    }

    // Now each cow has positions pos[id][0..4]
    // The key observation: compare any two cows A and B.
    // In the original ordering, if A comes before B, then in the 4 photos where neither of them moved,
    // A must be before B. In the photo where one of them moved, that cow's position changed.
    // So A is before B in the original order iff A is before B in AT LEAST 3 out of the 5 photos.
    // Because the only photo where the order might flip is the one where one of them moved.
    // (If both didn't move in a photo, the relative order stays as original.
    //  The cow that moved could go anywhere, potentially flipping the order.)
    // So we sort cows by this comparator.
    //
    // We'll collect all N IDs, sort them using this custom comparator.

    vector<int> ids;
    for (auto &kv : pos) {
        ids.push_back(kv.first);
    }

    sort(ids.begin(), ids.end(), [&](int a, int b) {
        const auto &pa = pos[a];
        const auto &pb = pos[b];
        int cnt = 0;
        for (int p = 0; p < 5; ++p) {
            if (pa[p] < pb[p]) ++cnt;
        }
        // If cnt >= 3, a should come before b
        // We want strict weak ordering: return true if a < b
        // Tie-breaking: if cnt == 2 or cnt == 3 exactly? Actually cnt == 3 means a before b in 3 photos, so a < b.
        // cnt == 2 means a before b in 2 photos, so b before a in 3 photos => b < a.
        // But we need to avoid inconsistent comparator (cnt == 2 => pa < pb in 2 photos, so return false).
        // For equal? IDs are distinct so positions vectors can't be all same.
        return cnt >= 3;
    });

    for (int i = 0; i < N; ++i) {
        if (i > 0) cout << ' ';
        cout << ids[i];
    }
    cout << '\n';

    return 0;
}
